export type Auth0PasswordStrengthProps = {
    value: string;
    show: boolean;
    schema: Yup.StringSchema<string, Yup.AnyObject, undefined, "">;
}
const Auth0PasswordStrength = ({
                                   value,
                                   show,
                                   schema
                               }: Auth0PasswordStrengthProps) => {

    /* const {t} = useLanguage()

     const hasLowerCase = /[a-z]/.test(value);
     const hasUpperCase = /[A-Z]/.test(value);
     const hasNumbers = /[0-9]/.test(value);
     const hasSpecialChars = /[\W_]/.test(value);

     const lengthMedium = value.length >= 8;
     const described = schema.describe();
     const messages = schema.describe().tests;*/

    const condition = (con: boolean) => {
        return con ? "green" : "red";
    };
    return (
        <Flex
            flexDirection={"column"}
            position={"absolute"}
            backgroundColor={"white"}
            pointerEvents={"none"}
            w={"100%"}
            top={"100%"}
            p={10}
            opacity={show ? 100 : 0}
            borderRadius={"lg"}
            fontSize={"sm"}
            zIndex={9999}
            shadow={"lg"}
        >
            {schema.tests.map((test, index) => {
                const msg = test.OPTIONS?.message;
                const name = test.OPTIONS?.name;

                if (name == 'required') return null
                const ctx: Partial<TestContext<any>> = {
                    path: 'password',
                    parent: {},
                    options: {},
                    originalValue: value,
                    resolve: (val: any) => val,
                    createError: (params) =>
                        new ValidationError(params?.message?.toString() ?? "", value, 'password'),
                };

                const testFn = test.OPTIONS?.test as (this: any, value: any) => any;
                const testing = testFn?.call(ctx, value);

                return <Flex flexDirection={"row"} alignItems={"center"} gap={10} key={index}>
                    <Flex>
                        <FaRegCircleCheck color={condition(!!testing)}/>
                    </Flex>
                    {typeof msg == 'string' ? <Text fontSize={13}>{msg}</Text> : <Text>{name}</Text>}
                </Flex>
            })}
            {/* <Flex flexDirection={"row"} alignItems={"center"} gap={10}>
                <Flex>
                    <FaRegCircleCheck color={condition(hasLowerCase)}/>
                </Flex>
                <Text>At least one lowercase letter.</Text>
            </Flex>
            <Flex flexDirection={"row"} alignItems={"center"} gap={10}>
                <Flex>
                    <FaRegCircleCheck color={condition(hasUpperCase)}/>
                </Flex>
                <Text>At least one uppercase letter.</Text>
            </Flex>
            <Flex flexDirection={"row"} alignItems={"center"} gap={10}>
                <Flex>
                    <FaRegCircleCheck color={condition(hasNumbers)}/>
                </Flex>
                <Text>At least one number.</Text>
            </Flex>
            <Flex flexDirection={"row"} alignItems={"center"} gap={10}>
                <Flex>
                    <FaRegCircleCheck color={condition(hasSpecialChars)}/>
                </Flex>
                <Text>At least one Symbol.</Text>
            </Flex>*/}
        </Flex>
    );
};

